var documenterSearchIndex = {"docs":
[{"category":"section","location":"references/#References","page":"References","text":"","title":"References"},{"category":"section","location":"references/#Parameter-Sources","page":"References","text":"P. Vogl, H.P. Hjalmarson, J.D. Dow, \"A semi-empirical tight-binding theory of the electronic structure of semiconductors,\" J. Phys. Chem. Solids 44, 365-378 (1983). DOI:10.1016/0022-3697(83)90064-1\nJ.-M. Jancu, R. Scholz, F. Beltram, F. Bassani, \"Empirical spds* tight-binding calculation for cubic semiconductors: General method and material parameters,\" Phys. Rev. B 57, 6493 (1998). DOI:10.1103/PhysRevB.57.6493\nG. Klimeck, R.C. Bowen, T.B. Boykin, T.A. Cwik, \"sp3s* tight-binding parameters for transport simulations in compound semiconductors,\" Superlattices and Microstructures 27, 519 (2000). DOI:10.1006/spmi.2000.0862","title":"Parameter Sources"},{"category":"section","location":"references/#Theory","page":"References","text":"J.C. Slater, G.F. Koster, \"Simplified LCAO Method for the Periodic Potential Problem,\" Phys. Rev. 94, 1498 (1954). DOI:10.1103/PhysRev.94.1498\nW.A. Harrison, Electronic Structure and the Properties of Solids, W.H. Freeman (1980). ISBN:978-0-486-66021-9","title":"Theory"},{"category":"section","location":"parameters/#Parameter-Sources","page":"Parameter Sources","text":"","title":"Parameter Sources"},{"category":"section","location":"parameters/#Overview","page":"Parameter Sources","text":"Parameters are retrieved using the three-axis dispatch: Model × Source × Material.\n\np = get_params(SP3Sstar, Vogl1983(), \"GaAs\")","title":"Overview"},{"category":"section","location":"parameters/#Available-Sources","page":"Parameter Sources","text":"","title":"Available Sources"},{"category":"section","location":"parameters/#Vogl-1983","page":"Parameter Sources","text":"Covers SP3 and SP3S* models for a wide range of III-V and group-IV semiconductors.","title":"Vogl 1983"},{"category":"section","location":"parameters/#Jancu-1998","page":"Parameter Sources","text":"Provides SP3D5S* parameters fitted to reproduce full-zone band structures.","title":"Jancu 1998"},{"category":"section","location":"parameters/#Klimeck-2000","page":"Parameter Sources","text":"Genetically-optimized SP3S*+SO parameters for accurate band edge properties.","title":"Klimeck 2000"},{"category":"section","location":"parameters/#Parameter-Types","page":"Parameter Sources","text":"SP3Params: NamedTuple with 12 parameters (on-site energies and hopping integrals for sp3 basis)\nSP3SstarParams: NamedTuple with 16 parameters (adds excited s* energies and hoppings)\n\nSP3 parameters can be extracted from SP3S* parameters via sp3_params.","title":"Parameter Types"},{"category":"section","location":"parameters/#Listing-Available-Materials","page":"Parameter Sources","text":"list_materials(Vogl1983())","title":"Listing Available Materials"},{"category":"section","location":"parameters/#Convenience-Instances","page":"Parameter Sources","text":"The singleton instances VOGL1983, JANCU1998, and KLIMECK2000 are also exported:\n\np = get_params(SP3Sstar, VOGL1983, \"GaAs\")  # equivalent","title":"Convenience Instances"},{"category":"section","location":"plotting/overview/#Plotting-Overview","page":"Overview","text":"EmpiricalTightBinding.jl provides two plotting paths:\n\nMethod Backend Use Case\nplot(bs) Plots.jl via RecipesBase Interactive exploration\nsavefig_publication(bs, ...) PythonPlot.jl (matplotlib) Publication figures with axis size control\n\nBoth use the BandStructure type as the common data interface.","title":"Plotting Overview"},{"category":"section","location":"examples/compare_models/#Comparing-Models","page":"Comparing Models","text":"","title":"Comparing Models"},{"category":"section","location":"examples/compare_models/#SP3-vs-SP3S*-for-GaAs","page":"Comparing Models","text":"The key difference between SP3 and SP3S* is the treatment of conduction bands. The excited s* orbital in SP3S* corrects the X-point conduction band minimum.\n\nusing EmpiricalTightBinding\n\nkp = vogl_kpath()\n\n# SP3S* model\np_sstar = get_params(SP3Sstar, Vogl1983(), \"GaAs\")\nbs_sstar = BandStructure(SP3Sstar(), kp, p_sstar; title=\"GaAs: SP3S* vs SP3\")\n\n# SP3 model\np_sp3 = get_params(SP3, Vogl1983(), \"GaAs\")\nbs_sp3 = BandStructure(SP3(), kp, p_sp3)","title":"SP3 vs SP3S* for GaAs"},{"category":"section","location":"examples/compare_models/#Plot-with-Plots.jl","page":"Comparing Models","text":"using Plots\n\nplot(bs_sstar)\nplot!(bs_sp3, linecolor=:blue, linestyle=:dash)\nsavefig(\"GaAs_sp3_vs_sp3sstar_plots.png\")","title":"Plot with Plots.jl"},{"category":"section","location":"examples/compare_models/#Plot-with-PythonPlot-(Publication-Quality)","page":"Comparing Models","text":"using PythonPlot\n\nsavefig_publication([bs_sstar, bs_sp3], \"GaAs_sp3_vs_sp3sstar.pdf\";\n    axis_width_cm=8.0, axis_height_cm=6.0,\n    layout=(1, 2))","title":"Plot with PythonPlot (Publication Quality)"},{"category":"section","location":"examples/compare_models/#SP3D5S*-for-Higher-Accuracy","page":"Comparing Models","text":"The SP3D5S* model with Jancu1998 parameters provides improved accuracy across the full Brillouin zone:\n\np_d = get_params(SP3D5Sstar, Jancu1998(), \"GaAs\")\nbs_d = BandStructure(SP3D5Sstar(), kp, p_d)","title":"SP3D5S* for Higher Accuracy"},{"category":"section","location":"examples/compare_models/#Plot-with-Plots.jl-2","page":"Comparing Models","text":"using Plots\n\nplot(bs_d)\nsavefig(\"GaAs_sp3d5sstar_plots.png\")","title":"Plot with Plots.jl"},{"category":"section","location":"examples/compare_models/#Plot-with-PythonPlot-(Publication-Quality)-2","page":"Comparing Models","text":"using PythonPlot\n\nsavefig_publication(bs_d, \"GaAs_sp3d5sstar.pdf\";\n    axis_width_cm=8.0, axis_height_cm=6.0)","title":"Plot with PythonPlot (Publication Quality)"},{"category":"section","location":"models/sp3/#SP3-Model","page":"SP3","text":"","title":"SP3 Model"},{"category":"section","location":"models/sp3/#Basis","page":"SP3","text":"8-band model with s and three p orbitals on each atom:\n\nIndex Anion Cation\n1, 5 s s\n2, 6 p_x p_x\n3, 7 p_y p_y\n4, 8 p_z p_z","title":"Basis"},{"category":"section","location":"models/sp3/#Parameters","page":"SP3","text":"The SP3 model uses SP3Params with 12 parameters:\n\nOn-site energies: Es, Ep for each atom\nHopping integrals: Vss, Vxx, Vxy, Vsapc, Vscpa\n\nSP3 parameters can be extracted from SP3S* parameters via sp3_params.","title":"Parameters"},{"category":"section","location":"models/sp3/#Available-Parameter-Sources","page":"SP3","text":"Source Materials\nVogl1983 Si, Ge, C, Sn, SiC, GaAs, GaP, GaSb, AlAs, AlP, AlSb, InAs, InP, InSb, ZnSe, ZnTe\nKlimeck2000 GaAs, GaP, GaSb, AlAs, AlP, AlSb, InAs, InP, InSb","title":"Available Parameter Sources"},{"category":"section","location":"models/sp3/#Limitations","page":"SP3","text":"The sp3 basis cannot reproduce indirect conduction band minima correctly. For quantitative work, use SP3Sstar or higher models.","title":"Limitations"},{"category":"section","location":"examples/compare_params/#Comparing-Parameter-Sets","page":"Comparing Parameter Sets","text":"","title":"Comparing Parameter Sets"},{"category":"section","location":"examples/compare_params/#GaAs:-Vogl-1983-vs-Klimeck-2000","page":"Comparing Parameter Sets","text":"Different parameter sources are fitted with different objectives:\n\nVogl1983: Fitted to reproduce key band energies at high-symmetry points.\nKlimeck2000: Genetically optimized to reproduce band edge effective masses and deformation potentials.\n\nusing EmpiricalTightBinding\n\nkp = vogl_kpath()\n\n# Vogl (1983)\np_vogl = get_params(SP3Sstar, Vogl1983(), \"GaAs\")\nbs_vogl = BandStructure(SP3Sstar(), kp, p_vogl; title=\"GaAs: Vogl 1983\")\n\n# Klimeck (2000)\np_klim = get_params(SP3Sstar, Klimeck2000(), \"GaAs\")\nbs_klim = BandStructure(SP3Sstar(), kp, p_klim; title=\"GaAs: Klimeck 2000\")","title":"GaAs: Vogl 1983 vs Klimeck 2000"},{"category":"section","location":"examples/compare_params/#Band-Gap-Comparison","page":"Comparing Parameter Sets","text":"gap_vogl = band_energies(SP3Sstar(), [0,0,0], p_vogl) |> e -> e[5] - e[4]\ngap_klim = band_energies(SP3Sstar(), [0,0,0], p_klim) |> e -> e[5] - e[4]\n\nprintln(\"Vogl 1983:    $(round(gap_vogl, digits=3)) eV\")\nprintln(\"Klimeck 2000: $(round(gap_klim, digits=3)) eV\")\nprintln(\"Experiment:   1.519 eV\")","title":"Band Gap Comparison"},{"category":"section","location":"examples/compare_params/#Plot-with-Plots.jl","page":"Comparing Parameter Sets","text":"using Plots\n\nplot(bs_vogl)\nplot!(bs_klim, linecolor=:blue, linestyle=:dash)\nsavefig(\"GaAs_vogl_vs_klimeck_plots.png\")","title":"Plot with Plots.jl"},{"category":"section","location":"examples/compare_params/#Plot-with-PythonPlot-(Publication-Quality)","page":"Comparing Parameter Sets","text":"using PythonPlot\n\nsavefig_publication([bs_vogl, bs_klim], \"GaAs_vogl_vs_klimeck.pdf\";\n    axis_width_cm=8.0, axis_height_cm=6.0,\n    layout=(1, 2))","title":"Plot with PythonPlot (Publication Quality)"},{"category":"section","location":"plotting/publication/#Publication-Figures","page":"Publication Figures","text":"For publication-quality figures with precise axis dimensions, use savefig_publication which calls matplotlib directly via PythonPlot.jl.","title":"Publication Figures"},{"category":"section","location":"plotting/publication/#Motivation","page":"Publication Figures","text":"Plots.jl does not support specifying axis (plot area) dimensions directly – only figure size can be set. For journal submissions, precise control over axis dimensions is often required. matplotlib provides this via fig.add_axes and fig.set_size_inches.","title":"Motivation"},{"category":"section","location":"plotting/publication/#Usage","page":"Publication Figures","text":"using EmpiricalTightBinding, PythonPlot\n\np = get_params(SP3Sstar, Vogl1983(), \"GaAs\")\nkp = vogl_kpath()\nbs = BandStructure(SP3Sstar(), kp, p)\n\nsavefig_publication(bs, \"bands.pdf\";\n    axis_width_cm=8.0, axis_height_cm=6.0)","title":"Usage"},{"category":"section","location":"plotting/publication/#Subplot-Support","page":"Publication Figures","text":"bs1 = BandStructure(SP3Sstar(), kp, p)\nbs2 = BandStructure(SP3(), kp, get_params(SP3, Vogl1983(), \"GaAs\"))\n\nsavefig_publication([bs1, bs2], \"compare.pdf\";\n    axis_width_cm=6.0, axis_height_cm=5.0,\n    layout=(1, 2))","title":"Subplot Support"},{"category":"section","location":"models/overview/#Models-Overview","page":"Overview","text":"EmpiricalTightBinding.jl provides a hierarchy of tight-binding models with increasing complexity.","title":"Models Overview"},{"category":"section","location":"models/overview/#Model-Comparison","page":"Overview","text":"Model Orbitals per atom Bands Spin-Orbit Reference\nSP3 s, p 8 No —\nSP3Sstar s, p, s* 10 No Vogl et al. (1983)\nSP3Sstar_SO s, p, s* × spin 20 Yes Klimeck et al. (2000)\nSP3D5Sstar s, p, d, s* 20 No Jancu et al. (1998)","title":"Model Comparison"},{"category":"section","location":"models/overview/#Choosing-a-Model","page":"Overview","text":"SP3: Simplest model. Gives qualitatively correct valence bands but poor conduction bands (no indirect gap in Si/Ge).\nSP3Sstar: Adds an excited s* orbital to fix the conduction band issue. The standard choice for most applications.\nSP3Sstar_SO: Adds spin-orbit coupling. Required for materials with significant spin-orbit (SO) splitting (e.g., InSb, GaSb).\nSP3D5Sstar: Adds d orbitals for improved accuracy across the full Brillouin zone. Best for quantitative work.","title":"Choosing a Model"},{"category":"section","location":"models/sp3sstar/#SP3S*-Model","page":"SP3S*","text":"","title":"SP3S* Model"},{"category":"section","location":"models/sp3sstar/#Basis","page":"SP3S*","text":"10-band model adding an excited s* orbital to the SP3 basis:\n\nIndex Anion Cation\n1, 6 s s\n2, 7 p_x p_x\n3, 8 p_y p_y\n4, 9 p_z p_z\n5, 10 s^* s^*","title":"Basis"},{"category":"section","location":"models/sp3sstar/#Parameters","page":"SP3S*","text":"Uses SP3SstarParams with 16 parameters, adding:\n\nOn-site energies: Es* for each atom\nHopping integrals: Vs*p and Vps*","title":"Parameters"},{"category":"section","location":"models/sp3sstar/#Available-Parameter-Sources","page":"SP3S*","text":"Source Materials\nVogl1983 Si, Ge, C, Sn, SiC, GaAs, GaP, GaSb, AlAs, AlP, AlSb, InAs, InP, InSb, ZnSe, ZnTe\nKlimeck2000 GaAs, GaP, GaSb, AlAs, AlP, AlSb, InAs, InP, InSb","title":"Available Parameter Sources"},{"category":"section","location":"models/sp3sstar/#Key-Feature","page":"SP3S*","text":"The excited s* orbital corrects the conduction band at the X point, enabling correct prediction of indirect band gaps in Si and Ge. This is the model introduced by Vogl, Hjalmarson, and Dow (1983).","title":"Key Feature"},{"category":"section","location":"models/sp3sstar/#Reference","page":"SP3S*","text":"P. Vogl, H.P. Hjalmarson, J.D. Dow, \"A semi-empirical tight-binding theory of the electronic structure of semiconductors,\" J. Phys. Chem. Solids 44, 365-378 (1983). DOI:10.1016/0022-3697(83)90064-1","title":"Reference"},{"category":"section","location":"models/sp3sstar_so/#SP3S*-Spin-Orbit-Model","page":"SP3S* + Spin-Orbit","text":"","title":"SP3S* + Spin-Orbit Model"},{"category":"section","location":"models/sp3sstar_so/#Basis","page":"SP3S* + Spin-Orbit","text":"20-band model that doubles the SP3S* basis with explicit spin:\n\nIndex 1-10 Spin-up Index 11-20 Spin-down\ns p_x p_y p_z s^* (anion) uparrow s p_x p_y p_z s^* (anion) downarrow\ns p_x p_y p_z s^* (cation) uparrow s p_x p_y p_z s^* (cation) downarrow","title":"Basis"},{"category":"section","location":"models/sp3sstar_so/#Spin-Orbit-Coupling","page":"SP3S* + Spin-Orbit","text":"Spin-orbit interaction is added as an on-site coupling between p orbitals of different spin. The spin-orbit splitting parameter Δ controls the strength of the coupling.","title":"Spin-Orbit Coupling"},{"category":"section","location":"models/sp3sstar_so/#Available-Parameter-Sources","page":"SP3S* + Spin-Orbit","text":"Source Materials\nVogl1983 Si, Ge, C, Sn, SiC, GaAs, GaP, GaSb, AlAs, AlP, AlSb, InAs, InP, InSb, ZnSe, ZnTe\nKlimeck2000 GaAs, GaP, GaSb, AlAs, AlP, AlSb, InAs, InP, InSb","title":"Available Parameter Sources"},{"category":"section","location":"models/sp3sstar_so/#When-to-Use","page":"SP3S* + Spin-Orbit","text":"Required for materials with significant spin-orbit splitting, such as InSb, GaSb, and other heavy-element semiconductors where the split-off band energy is important.","title":"When to Use"},{"category":"section","location":"models/sp3sstar_so/#Reference","page":"SP3S* + Spin-Orbit","text":"G. Klimeck, R.C. Bowen, T.B. Boykin, T.A. Cwik, \"sp3s* tight-binding parameters for transport simulations in compound semiconductors,\" Superlattices and Microstructures 27, 519 (2000). DOI:10.1006/spmi.2000.0862","title":"Reference"},{"category":"section","location":"examples/gaas/#GaAs-Band-Structure","page":"GaAs Band Structure","text":"","title":"GaAs Band Structure"},{"category":"section","location":"examples/gaas/#Compute-Band-Structure","page":"GaAs Band Structure","text":"using EmpiricalTightBinding\n\np = get_params(SP3Sstar, Vogl1983(), \"GaAs\")\nkp = vogl_kpath()\nbs = BandStructure(SP3Sstar(), kp, p)\n\n# Check band gap at Γ\nevals = band_energies(SP3Sstar(), [0, 0, 0], p)\nvbm = evals[4]\ncbm = evals[5]\nprintln(\"Direct gap at Γ: $(cbm - vbm) eV\")","title":"Compute Band Structure"},{"category":"section","location":"examples/gaas/#Plot-with-Plots.jl","page":"GaAs Band Structure","text":"using Plots\n\nplot(bs)\nsavefig(\"GaAs_bands_plots.png\")","title":"Plot with Plots.jl"},{"category":"section","location":"examples/gaas/#Plot-with-PythonPlot-(Publication-Quality)","page":"GaAs Band Structure","text":"using PythonPlot\n\nsavefig_publication(bs, \"GaAs_bands.pdf\";\n    axis_width_cm=8.0, axis_height_cm=6.0)","title":"Plot with PythonPlot (Publication Quality)"},{"category":"section","location":"examples/gaas/#Comparing-with-SP3","page":"GaAs Band Structure","text":"The SP3 model (without s*) gives qualitatively different conduction bands:\n\np_sp3 = get_params(SP3, Vogl1983(), \"GaAs\")\nbs_sp3 = BandStructure(SP3(), kp, p_sp3)","title":"Comparing with SP3"},{"category":"section","location":"guide/#Getting-Started","page":"Getting Started","text":"","title":"Getting Started"},{"category":"section","location":"guide/#Basic-Workflow","page":"Getting Started","text":"A typical band structure calculation has three steps:","title":"Basic Workflow"},{"category":"section","location":"guide/#1.-Choose-model-and-parameters","page":"Getting Started","text":"using EmpiricalTightBinding\n\n# SP3S* model with Vogl (1983) parameters for GaAs\np = get_params(SP3Sstar, Vogl1983(), \"GaAs\")\n\nAvailable combinations depend on which parameter sources support which models:\n\nSource Models Materials\nVogl1983 SP3, SP3Sstar Si, Ge, GaAs, GaP, InAs, InP, ...\nJancu1998 SP3D5Sstar Si, Ge, GaAs, ...\nKlimeck2000 SP3Sstar GaAs, InAs, ...\n\nUse list_materials to see available materials:\n\nlist_materials(Vogl1983())","title":"1. Choose model and parameters"},{"category":"section","location":"guide/#2.-Build-a-k-path","page":"Getting Started","text":"# Predefined Vogl Fig.1 path: L → Γ → X → U,K → Γ\nkp = vogl_kpath()\n\n# Or a simple textbook path: L → Γ → X\nkp = textbook_kpath()\n\n# Or custom\nkp = make_kpath([:L => :Γ, :Γ => :X])\n\nSee K-Paths & Brillouin Zone for details on vogl_kpath, textbook_kpath, and make_kpath.","title":"2. Build a k-path"},{"category":"section","location":"guide/#3.-Compute-band-structure","page":"Getting Started","text":"bands = compute_bands(SP3Sstar(), kp, p)\n# Returns nk × nbands matrix, VBM aligned to 0\n\ncompute_bands returns a matrix of eigenvalues (in the same units as the input parameters), with the valence band maximum aligned to 0 by default.","title":"3. Compute band structure"},{"category":"section","location":"guide/#Single-k-point-Calculation","page":"Getting Started","text":"For eigenvalues at a single k-point, use band_energies:\n\nevals = band_energies(SP3Sstar(), [0.0, 0.0, 0.0], p)","title":"Single k-point Calculation"},{"category":"section","location":"guide/#Direct-Hamiltonian-Access","page":"Getting Started","text":"Use build_hamiltonian to get the Hamiltonian matrix directly:\n\nH = build_hamiltonian(SP3Sstar(), [0.3, 0.2, 0.1], p)\n# Returns Hermitian{ComplexF64} matrix","title":"Direct Hamiltonian Access"},{"category":"section","location":"api/#API-Reference","page":"API Reference","text":"","title":"API Reference"},{"category":"section","location":"api/#Models","page":"API Reference","text":"","title":"Models"},{"category":"section","location":"api/#Parameters","page":"API Reference","text":"","title":"Parameters"},{"category":"section","location":"api/#Band-Structure","page":"API Reference","text":"","title":"Band Structure"},{"category":"section","location":"api/#K-Paths","page":"API Reference","text":"","title":"K-Paths"},{"category":"section","location":"api/#Plotting","page":"API Reference","text":"","title":"Plotting"},{"category":"type","location":"api/#EmpiricalTightBinding.SP3","page":"API Reference","text":"8-band sp³ model (s, px, py, pz on anion + cation).\n\n\n\n\n\n","title":"EmpiricalTightBinding.SP3"},{"category":"type","location":"api/#EmpiricalTightBinding.SP3Sstar","page":"API Reference","text":"10-band sp³s* model (Vogl et al. 1983). Adds excited s* on each atom.\n\n\n\n\n\n","title":"EmpiricalTightBinding.SP3Sstar"},{"category":"type","location":"api/#EmpiricalTightBinding.SP3Sstar_SO","page":"API Reference","text":"20-band sp³s* + spin-orbit model. Doubles basis with spin.\n\n\n\n\n\n","title":"EmpiricalTightBinding.SP3Sstar_SO"},{"category":"type","location":"api/#EmpiricalTightBinding.SP3D5Sstar","page":"API Reference","text":"20-band sp³d⁵s* model (Jancu et al. 1998). Adds five d orbitals per atom.\n\n\n\n\n\n","title":"EmpiricalTightBinding.SP3D5Sstar"},{"category":"function","location":"api/#EmpiricalTightBinding.hamiltonian_size","page":"API Reference","text":"Hamiltonian matrix dimension for each model.\n\n\n\n\n\n","title":"EmpiricalTightBinding.hamiltonian_size"},{"category":"function","location":"api/#EmpiricalTightBinding.build_hamiltonian","page":"API Reference","text":"build_hamiltonian(model::TBModel, k, params) -> Hermitian{ComplexF64}\n\nBuild the tight-binding Hamiltonian at wave vector k (in units of 2π/a). Dispatches on the model type.\n\n\n\n\n\n","title":"EmpiricalTightBinding.build_hamiltonian"},{"category":"type","location":"api/#EmpiricalTightBinding.Vogl1983","page":"API Reference","text":"Vogl1983\n\nP. Vogl, H.P. Hjalmarson, J.D. Dow, \"A semi-empirical tight-binding theory of the electronic structure of semiconductors,\" J. Phys. Chem. Solids 44, 365-378 (1983). DOI: 10.1016/0022-3697(83)90064-1\n\nsp³s* parameters for group-IV and III-V zinc-blende semiconductors. All energies are in eV. Supports models: SP3, SP3Sstar, SP3Sstar_SO.\n\n\n\n\n\n","title":"EmpiricalTightBinding.Vogl1983"},{"category":"type","location":"api/#EmpiricalTightBinding.Klimeck2000","page":"API Reference","text":"Klimeck2000\n\nG. Klimeck, R.C. Bowen, T.B. Boykin, T.A. Cwik, \"sp3s* tight-binding parameters for transport simulations in compound semiconductors,\" Superlattices and Microstructures 27, 519 (2000). DOI: 10.1006/spmi.2000.0862\n\nGenetically-optimized sp³s*+SO parameters for III-V compound semiconductors. All energies are in eV. Supports models: SP3, SP3Sstar, SP3Sstar_SO.\n\n\n\n\n\n","title":"EmpiricalTightBinding.Klimeck2000"},{"category":"type","location":"api/#EmpiricalTightBinding.Jancu1998","page":"API Reference","text":"Jancu1998\n\nJ.-M. Jancu, R. Scholz, F. Beltram, F. Bassani, \"Empirical spds* tight-binding calculation for cubic semiconductors: General method and material parameters,\" Phys. Rev. B 57, 6493 (1998). DOI: 10.1103/PhysRevB.57.6493\n\nsp³d⁵s* parameters for group-IV and III-V zinc-blende semiconductors. All energies are in eV. Supports model: SP3D5Sstar.\n\n\n\n\n\n","title":"EmpiricalTightBinding.Jancu1998"},{"category":"function","location":"api/#EmpiricalTightBinding.list_sources","page":"API Reference","text":"list_sources() -> Vector\n\nReturn all available parameter source types (subtypes of ParamSource). Includes sources added at runtime.\n\nExample\n\nlist_sources()\n# 3-element Vector{Any}:\n#  Jancu1998\n#  Klimeck2000\n#  Vogl1983\n\n\n\n\n\n","title":"EmpiricalTightBinding.list_sources"},{"category":"function","location":"api/#EmpiricalTightBinding.list_materials","page":"API Reference","text":"list_materials(source::ParamSource)\n\nPrint available materials for a given parameter source. The output format varies by source (e.g., crystal type, lattice constant).\n\nExample\n\nlist_materials(Vogl1983())\nlist_materials(Jancu1998())\n\n\n\n\n\n","title":"EmpiricalTightBinding.list_materials"},{"category":"function","location":"api/#EmpiricalTightBinding.sp3_params","page":"API Reference","text":"sp3_params(p::SP3SstarParams) -> SP3Params\n\nExtract the sp3 subset from sp3s* parameters.\n\n\n\n\n\n","title":"EmpiricalTightBinding.sp3_params"},{"category":"function","location":"api/#EmpiricalTightBinding.compute_bands","page":"API Reference","text":"compute_bands(model::TBModel, kpath::KPath, params;\n              align=:VBM, material=\"\") -> Matrix{Float64}\n\nCompute eigenvalues along a k-path. Returns nk × nbands matrix of eigenvalues (in the same units as the input parameters).\n\nalign=:VBM: shift so VBM = 0 (requires material for n_valence)\nalign=:none: no shift (raw eigenvalues)\n\n\n\n\n\n","title":"EmpiricalTightBinding.compute_bands"},{"category":"function","location":"api/#EmpiricalTightBinding.band_energies","page":"API Reference","text":"band_energies(model::TBModel, k, params) -> Vector{Float64}\n\nCompute eigenvalues at a single k-point (raw, no shift).\n\n\n\n\n\n","title":"EmpiricalTightBinding.band_energies"},{"category":"function","location":"api/#EmpiricalTightBinding.n_valence","page":"API Reference","text":"n_valence(model::TBModel, material::String) -> Int\n\nNumber of filled valence bands. Without spin-orbit: 4 (8 electrons / 2 spin). With spin-orbit: 8 (spin explicitly in basis).\n\n\n\n\n\n","title":"EmpiricalTightBinding.n_valence"},{"category":"type","location":"api/#EmpiricalTightBinding.KPath","page":"API Reference","text":"KPath\n\nDiscretized k-path through the Brillouin zone. Stores k-points, cumulative distances, and tick info for plotting.\n\n\n\n\n\n","title":"EmpiricalTightBinding.KPath"},{"category":"function","location":"api/#EmpiricalTightBinding.make_kpath","page":"API Reference","text":"make_kpath(segments; nk=100, kpoints=FCC_KPOINTS)\n\nBuild a KPath from a list of segment specifications.\n\nEach segment is a Pair of symbols or vectors:\n\n(:L => :Γ) — uses named high-symmetry points\n([0.5,0.5,0.5] => [0.0,0.0,0.0]) — explicit coordinates\n\nMultiple segments can be separated by nothing to indicate a discontinuity (e.g., U,K jump in Vogl Fig.1).\n\nExample (Vogl Fig.1 path)\n\nkp = make_kpath([\n    :L => :Γ, :Γ => :X, :X => :U,\n    nothing,  # discontinuity\n    :K => :Γ\n])\n\n\n\n\n\n","title":"EmpiricalTightBinding.make_kpath"},{"category":"function","location":"api/#EmpiricalTightBinding.vogl_kpath","page":"API Reference","text":"vogl_kpath(; nk=100)\n\nStandard Vogl Fig.1 k-path: L → Γ → X → U,K → Γ\n\n\n\n\n\n","title":"EmpiricalTightBinding.vogl_kpath"},{"category":"function","location":"api/#EmpiricalTightBinding.textbook_kpath","page":"API Reference","text":"textbook_kpath(; nk=100)\n\nSimple textbook k-path: L → Γ → X\n\n\n\n\n\n","title":"EmpiricalTightBinding.textbook_kpath"},{"category":"constant","location":"api/#EmpiricalTightBinding.FCC_KPOINTS","page":"API Reference","text":"High-symmetry k-points for FCC/zinc-blende (in units of 2π/a).\n\n\n\n\n\n","title":"EmpiricalTightBinding.FCC_KPOINTS"},{"category":"type","location":"api/#EmpiricalTightBinding.BandStructure","page":"API Reference","text":"BandStructure\n\nPrecomputed band structure data, independent of any plotting library.\n\nFields\n\nx::Vector{Float64} — cumulative k-path distances\nbands::Matrix{Float64} — eigenvalues, nk × nbands (same units as input parameters)\ntick_positions::Vector{Float64} — high-symmetry point positions\ntick_labels::Vector{String} — high-symmetry point labels\ntitle::String — plot title\n\n\n\n\n\n","title":"EmpiricalTightBinding.BandStructure"},{"category":"function","location":"api/#EmpiricalTightBinding.savefig_publication","page":"API Reference","text":"savefig_publication(bs::BandStructure, path::AbstractString; kwargs...)\nsavefig_publication(bss::AbstractVector{<:BandStructure}, path::AbstractString; kwargs...)\n\nSave publication-quality band structure figure with precise axis dimensions. Requires using PythonPlot.\n\nKeywords\n\naxis_width_cm: axis width in cm (default: 8.0)\naxis_height_cm: axis height in cm (default: 6.0)\nlayout: subplot layout tuple, e.g., (1, 2) (for vector input)\n\nExample\n\nusing PythonPlot\nsavefig_publication(bs, \"bands.pdf\"; axis_width_cm=8.0, axis_height_cm=6.0)\n\n\n\n\n\n","title":"EmpiricalTightBinding.savefig_publication"},{"category":"section","location":"kpaths/#K-Paths-and-Brillouin-Zone","page":"K-Paths & Brillouin Zone","text":"","title":"K-Paths & Brillouin Zone"},{"category":"section","location":"kpaths/#FCC-Brillouin-Zone","page":"K-Paths & Brillouin Zone","text":"EmpiricalTightBinding.jl provides high-symmetry k-points for the FCC/zinc-blende Brillouin zone (in units of 2π/a):\n\nPoint Coordinates\nΓ (0, 0, 0)\nX (1, 0, 0)\nL (1/2, 1/2, 1/2)\nK (3/4, 3/4, 0)\nU (1, 1/4, 1/4)\nW (1, 1/2, 0)","title":"FCC Brillouin Zone"},{"category":"section","location":"kpaths/#Predefined-Paths","page":"K-Paths & Brillouin Zone","text":"vogl_kpath(; nk=100): L → Γ → X → U,K → Γ (Vogl Fig.1)\ntextbook_kpath(; nk=100): L → Γ → X","title":"Predefined Paths"},{"category":"section","location":"kpaths/#Custom-Paths","page":"K-Paths & Brillouin Zone","text":"Build custom paths with make_kpath:\n\n# W → L → Γ → X → W → K\nkp = make_kpath([:W => :L, :L => :Γ, :Γ => :X, :X => :W, :W => :K])","title":"Custom Paths"},{"category":"section","location":"kpaths/#Discontinuities","page":"K-Paths & Brillouin Zone","text":"Use nothing to indicate a jump (e.g., U,K point in the Vogl path):\n\nkp = make_kpath([\n    :L => :Γ, :Γ => :X, :X => :U,\n    nothing,\n    :K => :Γ\n])","title":"Discontinuities"},{"category":"section","location":"theory/#Theory","page":"Theory","text":"","title":"Theory"},{"category":"section","location":"theory/#Empirical-Tight-Binding-Method","page":"Theory","text":"The empirical tight-binding method expands electronic states in a basis of atomic-like orbitals localized on each atom. For a zinc-blende crystal with two atoms per unit cell (anion and cation), the Bloch Hamiltonian at wave vector mathbfk takes the form:\n\nH(mathbfk) = beginpmatrix E_a  V(mathbfk)  V^dagger(mathbfk)  E_c endpmatrix\n\nwhere E_a and E_c are diagonal on-site energy matrices for the anion and cation, V(mathbfk) contains the hopping (off-diagonal) terms modulated by structure factors, and V^dagger is the conjugate transpose of V.","title":"Empirical Tight-Binding Method"},{"category":"section","location":"theory/#Structure-Factors","page":"Theory","text":"For the zinc-blende structure (FCC lattice with two-atom basis), the nearest-neighbor structure factors are:\n\ng_0(mathbfk) = frac14left(e^ipi(k_1+k_2+k_3)2 + e^ipi(-k_1-k_2+k_3)2 + e^ipi(-k_1+k_2-k_3)2 + e^ipi(k_1-k_2-k_3)2right)\n\nwith g_1 g_2 g_3 formed by sign changes on the individual exponentials. These factors encode the crystal geometry and modulate the Slater-Koster hopping integrals.","title":"Structure Factors"},{"category":"section","location":"theory/#Slater-Koster-Parameters","page":"Theory","text":"The hopping matrix elements between orbitals are parameterized using the Slater-Koster two-center integrals (V_sssigma, V_spsigma, V_ppsigma, V_pppi, etc.). These parameters are fitted to reproduce experimental or first-principles band structures at high-symmetry points.","title":"Slater-Koster Parameters"},{"category":"section","location":"theory/#References","page":"Theory","text":"J.C. Slater, G.F. Koster, \"Simplified LCAO Method for the Periodic Potential Problem,\" Phys. Rev. 94, 1498 (1954). DOI:10.1103/PhysRev.94.1498\nSee also the References page for parameter source publications.","title":"References"},{"category":"section","location":"plotting/plots/#Plots.jl-Integration","page":"Plots.jl (Recipe)","text":"Band structures can be plotted using Plots.jl via a RecipesBase recipe.","title":"Plots.jl Integration"},{"category":"section","location":"plotting/plots/#Usage","page":"Plots.jl (Recipe)","text":"using EmpiricalTightBinding, Plots\n\np = get_params(SP3Sstar, Vogl1983(), \"GaAs\")\nkp = vogl_kpath()\n\nbs = BandStructure(SP3Sstar(), kp, p)\nplot(bs)","title":"Usage"},{"category":"section","location":"plotting/plots/#Overlaying-Band-Structures","page":"Plots.jl (Recipe)","text":"bs1 = BandStructure(SP3Sstar(), kp, p; title=\"GaAs: SP3S* vs SP3\")\nbs2 = BandStructure(SP3(), kp, get_params(SP3, Vogl1983(), \"GaAs\"))\n\nplot(bs1)\nplot!(bs2, linecolor=:blue, linestyle=:dash)","title":"Overlaying Band Structures"},{"category":"section","location":"plotting/plots/#Customization","page":"Plots.jl (Recipe)","text":"All standard Plots.jl keyword arguments are supported:\n\nplot(bs; ylims=(-5, 10), size=(800, 600), linecolor=:red)","title":"Customization"},{"category":"section","location":"models/sp3d5sstar/#SP3D5S*-Model","page":"SP3D5S*","text":"","title":"SP3D5S* Model"},{"category":"section","location":"models/sp3d5sstar/#Basis","page":"SP3D5S*","text":"20-band model adding five d orbitals per atom to the SP3S* basis:\n\nIndex Anion Cation\n1, 11 s s\n2-4, 12-14 p_x p_y p_z p_x p_y p_z\n5-9, 15-19 d_xy d_yz d_zx d_x^2-y^2 d_3z^2-r^2 d_xy ldots\n10, 20 s^* s^*","title":"Basis"},{"category":"section","location":"models/sp3d5sstar/#Parameters","page":"SP3D5S*","text":"Uses an extended parameter set with additional Slater-Koster integrals:\n\nd on-site energies\ns-d, p-d, and d-d hopping integrals","title":"Parameters"},{"category":"section","location":"models/sp3d5sstar/#Available-Parameter-Sources","page":"SP3D5S*","text":"Source Materials\nJancu1998 Si, Ge, C, Sn, SiC, GaAs, GaP, GaSb, AlAs, AlP, AlSb, InAs, InP, InSb, ZnSe, ZnTe","title":"Available Parameter Sources"},{"category":"section","location":"models/sp3d5sstar/#Key-Feature","page":"SP3D5S*","text":"The d orbitals provide improved accuracy for the full Brillouin zone, particularly for higher conduction bands.","title":"Key Feature"},{"category":"section","location":"models/sp3d5sstar/#Reference","page":"SP3D5S*","text":"J.-M. Jancu, R. Scholz, F. Beltram, F. Bassani, \"Empirical spds* tight-binding calculation for cubic semiconductors: General method and material parameters,\" Phys. Rev. B 57, 6493 (1998). DOI:10.1103/PhysRevB.57.6493","title":"Reference"},{"category":"section","location":"#EmpiricalTightBinding.jl","page":"Home","text":"Empirical tight-binding band structure calculations for zinc-blende semiconductors.","title":"EmpiricalTightBinding.jl"},{"category":"section","location":"#Features","page":"Home","text":"Multiple tight-binding models: SP3, SP3S*, SP3S*+SO, SP3D5S*\nMultiple parameter sources: Vogl 1983, Jancu 1998, Klimeck 2000\nFlexible k-path construction for FCC Brillouin zone\nPlot recipes for Plots.jl integration","title":"Features"},{"category":"section","location":"#Quick-Start","page":"Home","text":"using EmpiricalTightBinding\nusing Plots\n\n# Get parameters\np = get_params(SP3Sstar, Vogl1983(), \"GaAs\")\n\n# Build k-path\nkp = vogl_kpath()\n\n# Compute and plot band structure\nbands = compute_bands(SP3Sstar(), kp, p)","title":"Quick Start"},{"category":"section","location":"#Installation","page":"Home","text":"using Pkg\nPkg.add(\"EmpiricalTightBinding\")","title":"Installation"},{"category":"section","location":"#Design-Concept:-Model-Source-Material","page":"Home","text":"EmpiricalTightBinding.jl is organized around three orthogonal axes:\n\nAxis Examples\nModel (basis set) SP3, SP3Sstar, SP3Sstar_SO, SP3D5Sstar\nSource (parameter set) Vogl1983, Jancu1998, Klimeck2000\nMaterial \"GaAs\", \"Si\", \"InP\", ...\n\nParameters are retrieved by specifying all three:\n\np = get_params(SP3Sstar, Vogl1983(), \"GaAs\")","title":"Design Concept: Model × Source × Material"}]
}
